import scala.collection.mutable

def solve(m: Long, n: Long, waitCost: Array[Array[Long]]): Long = {
    val rows = m.toInt
    val cols = n.toInt
    val dp = Array.fill(rows, cols, 2)(Long.MaxValue)
    val pq = mutable.PriorityQueue.empty[(Long, Int, Int, Int)](Ordering.by(-_._1))

    // Initial state: (totalCost, i, j, stepParity)
    // stepParity: 0 for odd step (move), 1 for even step (wait)
    val initialCost = (0 + 1) * (0 + 1)
    dp(0)(0)(0) = initialCost
    pq.enqueue((initialCost, 0, 0, 0))

    val directions = Array((1, 0), (0, 1)) // down and right

    while (pq.nonEmpty) {
        val (currentCost, i, j, parity) = pq.dequeue()
        if (i == rows - 1 && j == cols - 1) {
            return currentCost
        }
        if (currentCost > dp(i)(j)(parity)) {
            // Already found a better path to this state
            continue
        }

        if (parity == 0) {
            // Odd step: move
            for ((di, dj) <- directions) {
                val ni = i + di
                val nj = j + dj
                if (ni < rows && nj < cols) {
                    val moveCost = (ni + 1) * (nj + 1)
                    val newCost = currentCost + moveCost
                    val newParity = 1
                    if (newCost < dp(ni)(nj)(newParity)) {
                        dp(ni)(nj)(newParity) = newCost
                        pq.enqueue((newCost, ni, nj, newParity))
                    }
                }
            }
        } else {
            // Even step: wait
            val waitCostHere = waitCost(i)(j)
            val newCost = currentCost + waitCostHere
            val newParity = 0
            if (newCost < dp(i)(j)(newParity)) {
                dp(i)(j)(newParity) = newCost
                pq.enqueue((newCost, i, j, newParity))
            }
        }
    }

    -1 // Should not reach here if path exists
}
```
